import{_ as o,C as a,o as n,c as r,E as i,a2 as s}from"./chunks/framework.CkaEw-3u.js";const f=JSON.parse('{"title":"Create a Morph Animation","description":"Transform smoothly from one string to another and refine the transition","frontmatter":{"title":"Create a Morph Animation","description":"Transform smoothly from one string to another and refine the transition","pageClass":"feature-guide","aside":false,"head":[["link",{"rel":"canonical","href":"https://mug-lab-3.github.io/mug-typography-docs/en/features/feature-morph.html"}],["meta",{"property":"og:type","content":"website"}],["meta",{"property":"og:site_name","content":"Mug Typography Manual"}],["meta",{"property":"og:locale","content":"en_US"}],["meta",{"property":"og:title","content":"Create a Morph Animation | Mug Typography Manual"}],["meta",{"property":"og:description","content":"Transform smoothly from one string to another and refine the transition"}],["meta",{"property":"og:url","content":"https://mug-lab-3.github.io/mug-typography-docs/en/features/feature-morph.html"}],["meta",{"property":"og:image","content":"https://mug-lab-3.github.io/mug-typography-docs/image/social-card.jpg"}],["meta",{"property":"og:image:type","content":"image/jpeg"}],["meta",{"property":"og:image:width","content":"1200"}],["meta",{"property":"og:image:height","content":"630"}],["meta",{"property":"og:image:alt","content":"Mug Typography Online Manual"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:site","content":"@MugLab3"}],["meta",{"name":"twitter:title","content":"Create a Morph Animation | Mug Typography Manual"}],["meta",{"name":"twitter:description","content":"Transform smoothly from one string to another and refine the transition"}],["meta",{"name":"twitter:image","content":"https://mug-lab-3.github.io/mug-typography-docs/image/social-card.jpg"}],["meta",{"name":"twitter:image:alt","content":"Mug Typography Online Manual"}]]},"headers":[],"relativePath":"en/features/feature-morph.md","filePath":"en/features/feature-morph.md"}'),h={name:"en/features/feature-morph.md"};function l(c,t,g,m,p,d){const e=a("FeatureHero");return n(),r("div",null,[i(e,{eyebrow:"MORPH & TRANSITION",title:"One word flows into the next",description:"Morph smoothly from one text to another, with letter shapes matched automatically. Place just two keyframes on Progress to create a transition in which the characters melt into one another.",image:"/image/morph.webp","image-alt":"Morph animation transforming one string into another","detail-link":"/en/reference/reference-global-settings#morph-animation","point-one":"Two keyframes to finish","point-two":"Natural morphing algorithm","point-three":"Works across text lengths"}),t[0]||(t[0]=s('<h2 id="how-to-use" tabindex="-1">How to Use <a class="header-anchor" href="#how-to-use" aria-label="Permalink to &quot;How to Use&quot;">​</a></h2><ol><li>Set <strong>Page</strong> to <code>Global Settings</code>.</li><li>Enter the source string in <strong>Text</strong>.</li><li>Turn on <strong>Enable Morph</strong> in <strong>Morph Animation</strong>.</li><li>Enter the destination string in <strong>To Text</strong>.</li><li>At the starting frame, set <strong>Progress</strong> to <code>0</code> and add a keyframe.</li><li>At the ending frame, set Progress to <code>1</code>.</li></ol><p><code>0</code> is the shape of Text, and <code>1</code> is the shape of To Text. Intermediate values interpolate the parts between the two. Adjust the spacing and curve between keyframes to control the feel of the speed.</p><h2 id="chaining-multiple-morphs" tabindex="-1">Chaining Multiple Morphs <a class="header-anchor" href="#chaining-multiple-morphs" aria-label="Permalink to &quot;Chaining Multiple Morphs&quot;">​</a></h2><p>You can also morph through three or more strings in sequence, like A→B→C.</p><ol><li>On the frame where the first morph completes, change <strong>Text</strong> to the same string as To Text and set a keyframe, then reset <strong>Progress</strong> to <code>0</code>.</li><li>On the same frame, change <strong>To Text</strong> to the next string and set a keyframe as well, then animate Progress to <code>1</code> again.</li></ol><p>The shape shown at Progress <code>1</code> is identical to the shape right after swapping Text and resetting to <code>0</code>, so the switch is invisible on screen. Repeat this to chain as many transitions as you like.</p><h2 id="adjusting-the-matching" tabindex="-1">Adjusting the Matching <a class="header-anchor" href="#adjusting-the-matching" aria-label="Permalink to &quot;Adjusting the Matching&quot;">​</a></h2><p>When the character counts or shapes differ substantially, the plugin estimates which source parts should transform into which destination parts.</p><table tabindex="0"><thead><tr><th>Parameter</th><th>When to Adjust It</th></tr></thead><tbody><tr><td><strong>Matching Strength</strong></td><td>When you want matching to prioritize parts with similar filled areas. At <code>0</code>, positional proximity is prioritized.</td></tr><tr><td><strong>Same Glyph Priority</strong></td><td>When both strings contain the same character and you want those matching characters connected first.</td></tr></tbody></table><h2 id="tips-for-a-clean-result" tabindex="-1">Tips for a Clean Result <a class="header-anchor" href="#tips-for-a-clean-result" aria-label="Permalink to &quot;Tips for a Clean Result&quot;">​</a></h2><ul><li>Check the motion with the default values first, and change parameters such as <strong>Matching Strength</strong> gradually only if parts cross unnaturally.</li><li>Increase Same Glyph Priority if you want the same character to remain in the same position.</li><li>For strings with very different shapes, shorten the time spent around the middle of Progress to make the complex transformation less noticeable.</li><li>If the vertical position wobbles, try <code>Baseline</code> for Vertical Alignment.</li><li>If matching does not behave as intended, try changing <strong>Horizontal Alignment</strong> from <code>Center</code> to <code>Left</code> or <code>Right</code>. Changing the positional relationship between characters also changes the matching result.</li></ul><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>How parts are divided depends on the font&#39;s outline structure. Even with the same strings, changing the font can change the morph matching and motion.</p></div>',13))])}const y=o(h,[["render",l]]);export{f as __pageData,y as default};
